#!/usr/bin/env bash
# workflow-1.sh — 欧站合规切入 SOP walkthrough for 跨境电商运营.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="跨境电商运营"
WORKFLOW="欧站合规切入"

usage() {
  cat <<EOF
workflow-1.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./workflow-1.sh             # interactive
  ./workflow-1.sh --dry-run
  ./workflow-1.sh --json
  ./workflow-1.sh --explain
  ./workflow-1.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "欧站合规切入" 工作流。

一句话: 从「想卖到欧洲」到「全链路合规, 不被限流 / 罚款 / 下架」, 60-180 天周期

入门 SOP 共 10 步, 失败模式自检 5 项。

相关心智模型:
  • 合规优先于流量: 在欧美主流站点, 新品类上线前先解决「能不能合规开卖」, 再考虑「能不能跑出量」。
  • 选品决定 90% 命运: 在亚马逊体系里, 一个品的最终成败 90% 在选品阶段已经决定, 后续运营只能放大这 10% 空间。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "目标国清单 + 类目核查 — VerpackG 是德国必须, 电子是 WEEE + 电池法"
  "VAT 注册策略 — 英国独立 + 欧盟 OSS 一站式 (适合 B2C ≥ €10k 跨境)"
  "找 VAT 服务商 — Avalara / Avask / hellotax 等. 关键是「能在所有目标国注册」"
  "VerpackG 德国包装法 — LUCID 注册 + 加入双系统 + 季度申报包装重量"
  "WEEE + 电池法 — 各国独立注册, 含电池产品强制"
  "CE 自我声明 — 大量品类强制. 部分类目需第三方检测 (玩具 / 高功率电气)"
  "GS 认证 — 德国安全认证 (玩具 / 工具 / 家电类)"
  "GPSR 2024-12 实施 — 欧盟设责任人 + listing 显示责任人地址"
  "Pan-EU FBA 资格申请 — 上面合规都搞定后才能开"
  "持续合规跟踪 — 法规年年变, 至少每季复查"
)
declare -a FAILURE_MODES=(
  "自己处理 VAT 几乎 100% 出错 (各国细则不同 + 季度申报漏一次罚款翻倍)"
  "选了便宜的 VAT 服务商, 漏报 / 错报, 一年罚款远超省下的代理费"
  "VerpackG 没注册就上架, 第一周被举报, 整个 ASIN 报废"
  "GPSR 没赶上 2024-12 deadline, 2025 春被批量下架"
  "用 IOSS 但单笔 > €150 错申报, 海关扣货"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "workflow-1-walkthrough"
fi
